#include <iostream>

class Point2D {
    int m_x{};
    int m_y{};
public:
    Point2D(int x, int y) : m_x{ x }, m_y{ y } {}
    int getX() const { return m_x; }
    int getY() const { return m_y; }
};

Point2D operator*(const Point2D& p, int s)
{
    return Point2D{ p.getX() * s, p.getY() * s };
}

Point2D operator*(int s, const Point2D& p)
{
    return p * s;
}

int main()
{
    int x{}, y{}, s{};
    std::cin >> x >> y >> s;

    Point2D p{ x, y };

    Point2D r1{ p * s };
    Point2D r2{ s * p };

    std::cout << '(' << r1.getX() << ", " << r1.getY() << ")\n";
    std::cout << '(' << r2.getX() << ", " << r2.getY() << ")\n";

    return 0;
}
